const filters = $input.item.json.body.filters || {};
const page = parseInt($input.item.json.body.page) || 1;

const limit = 7;
const offset = (page - 1) * limit;

const conditions = [];
const params = [];
let paramIndex = 1;

let query = `
SELECT 
  id, name, surname, email, "roleId" AS role_id, password, enabled, NULL::timestamp AS created_at,
  COUNT(*) OVER() as total_count
FROM "user"
WHERE 1=1
`;

if (filters.searchText && typeof filters.searchText === 'string' && filters.searchText.trim() !== '') {
  conditions.push(`(
    CONCAT(name, ' ', surname) ILIKE $${paramIndex}
    OR email ILIKE $${paramIndex}
  )`);
  params.push(`%${filters.searchText}%`);
  paramIndex++;
}

if (filters.status !== undefined && filters.status !== null && filters.status !== '') {
  conditions.push(`enabled = $${paramIndex}`);
  params.push(filters.status);
  paramIndex++;
}

if ((filters.role_id !== undefined && filters.role_id !== null && filters.role_id !== '') || (filters.roleId !== undefined && filters.roleId !== null && filters.roleId !== '') || (filters.roleid !== undefined && filters.roleid !== null && filters.roleid !== '')) {
  conditions.push(`"roleId" = $${paramIndex}`);
  params.push(filters.role_id ?? filters.roleId ?? filters.roleid);
  paramIndex++;
}

if (conditions.length > 0) {
  query += ' AND ' + conditions.join(' AND ');
}

query += ` ORDER BY id DESC LIMIT ${limit} OFFSET ${offset}`;

return [
  {
    json: {
      query,
      params,
      page,
      limit
    }
  }
];
